# @cctt_verify {"v":2,"sym":"sympy.core.tests.test_logic.test_logic_fromstring","kind":"function","src_hash":"d5bdbadad5ffef33","in":{"base":"Any"},"out":{"base":"Any","pred":"S('a') == 'a' and S('!a') == Not('a') and S('a & b') == And('a', 'b') and S('a | b') == Or('a', 'b') and S('a | b & c') == And(Or('a', 'b'), 'c') and S('a & b | c') == Or(And('a', 'b'), 'c') and S('a & b & c') == And('a', 'b', 'c') and S('a | b | c') == Or('a', 'b', 'c')"},"spec":{"lhs":"test_logic_fromstring()","rhs":"test_logic_fromstring produces the expected output","over":{"base":"Any"},"name":"test_logic_fromstring_correct"},"guarantee":"test_logic_fromstring produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.core.tests.test_logic.test_logic_fromstring_correct","statement":"Path(test_logic_fromstring(x), test_logic_fromstring produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"41da480a8e99ac30"}
def test_logic_fromstring():
    S = Logic.fromstring

    assert S('a') == 'a'
    assert S('!a') == Not('a')
    assert S('a & b') == And('a', 'b')
    assert S('a | b') == Or('a', 'b')
    assert S('a | b & c') == And(Or('a', 'b'), 'c')
    assert S('a & b | c') == Or(And('a', 'b'), 'c')
    assert S('a & b & c') == And('a', 'b', 'c')
    assert S('a | b | c') == Or('a', 'b', 'c')

    raises(ValueError, lambda: S('| a'))
    raises(ValueError, lambda: S('& a'))
    raises(ValueError, lambda: S('a | | b'))
    raises(ValueError, lambda: S('a | & b'))
    raises(ValueError, lambda: S('a & & b'))
    raises(ValueError, lambda: S('a |'))
    raises(ValueError, lambda: S('a|b'))
    raises(ValueError, lambda: S('!'))
    raises(ValueError, lambda: S('! a'))
    raises(ValueError, lambda: S('!(a + 1)'))
    raises(ValueError, lambda: S(''))


